DROP TABLE IF EXISTS `leave_request`;
CREATE TABLE `leave_request`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `request_no` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '请假单号',
  `applicant_id` bigint NOT NULL COMMENT '申请人账号ID',
  `org_unit_id` bigint NOT NULL COMMENT '申请时所属组织ID',
  `leave_type_id` bigint NOT NULL COMMENT '假别ID',
  `approval_rule_id` bigint NOT NULL COMMENT '匹配规则ID',
  `applicant_name_snapshot` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '申请人姓名快照',
  `applicant_type` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '申请人类型快照',
  `position_level_code` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '岗位级别快照',
  `job_title_snapshot` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '职务快照',
  `team_leader_snapshot` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '班组长信息快照',
  `start_date` date NOT NULL COMMENT '开始日期',
  `end_date` date NOT NULL COMMENT '结束日期',
  `start_time` datetime NULL DEFAULT NULL COMMENT '开始时间',
  `end_time` datetime NULL DEFAULT NULL COMMENT '结束时间',
  `leave_days` decimal(8, 2) NOT NULL COMMENT '请假天数',
  `allowed_days` decimal(8, 2) NULL DEFAULT NULL COMMENT '制度允许天数',
  `exceeds_one_month` tinyint NOT NULL DEFAULT 0 COMMENT '是否超过一个月',
  `reason` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '请假理由',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '备注',
  `status` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'DRAFT' COMMENT '状态',
  `current_step` int NOT NULL DEFAULT 0 COMMENT '当前审批步骤',
  `current_action_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '当前节点类型',
  `submitted_by` bigint NULL DEFAULT NULL COMMENT '提报人账号ID',
  `submitted_at` datetime NULL DEFAULT NULL COMMENT '提交时间',
  `final_approved_at` datetime NULL DEFAULT NULL COMMENT '最终通过时间',
  `created_by` bigint NULL DEFAULT NULL COMMENT '创建人账号ID',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_leave_request_request_no`(`request_no` ASC) USING BTREE,
  INDEX `idx_leave_request_applicant_id`(`applicant_id` ASC) USING BTREE,
  INDEX `idx_leave_request_org_unit_id`(`org_unit_id` ASC) USING BTREE,
  INDEX `idx_leave_request_leave_type_id`(`leave_type_id` ASC) USING BTREE,
  INDEX `idx_leave_request_rule_id`(`approval_rule_id` ASC) USING BTREE,
  INDEX `idx_leave_request_status`(`status` ASC) USING BTREE,
  INDEX `fk_leave_request_submitted_by`(`submitted_by` ASC) USING BTREE,
  INDEX `fk_leave_request_created_by`(`created_by` ASC) USING BTREE,
  CONSTRAINT `fk_leave_request_applicant` FOREIGN KEY (`applicant_id`) REFERENCES `user_account` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `fk_leave_request_approval_rule` FOREIGN KEY (`approval_rule_id`) REFERENCES `approval_rule` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `fk_leave_request_created_by` FOREIGN KEY (`created_by`) REFERENCES `user_account` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `fk_leave_request_leave_type` FOREIGN KEY (`leave_type_id`) REFERENCES `leave_type` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `fk_leave_request_org_unit` FOREIGN KEY (`org_unit_id`) REFERENCES `org_unit` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `fk_leave_request_submitted_by` FOREIGN KEY (`submitted_by`) REFERENCES `user_account` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 14 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '请假申请主表' ROW_FORMAT = DYNAMIC;

